  param('id').isInt({ min: 1, max: 2_147_483_647 }).toInt(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // ... look up user
    return res.json({ id: req.params.id });
  },
);

// Centralized error handler — MUST have 4 args
app.use((err, req, res, _next) => {
  // Log full error server-side, return safe message client-side
  console.error({ msg: 'request_error', err: err.message, stack: err.stack });
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal Server Error' : err.message,
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => {
    server.close(() => process.exit(0));
    // Force exit if shutdown hangs
    setTimeout(() => process.exit(1), 10_000).unref();
  });
}

// Surface unhandled errors rather than silently swallowing them
process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandled_rejection', reason });
});

module.exports = app;
```

